mapper.select:
SELECT fee_name AS groupKey, COUNT(*) AS transactionCount, SUM(receivable) AS totalAmount, SUM(discount_amount) AS discountAmount, SUM(overdue_fee) AS overdueAmount, 0 AS prePayAmount, SUM(paid_amount) AS payAmount FROM resi_receivable WHERE delete_time IS NULL AND pay_state = '2'
AND project_id = #{projectId}
AND project_id IN
#{pid}
GROUP BY fee_name ORDER BY SUM(paid_amount) DESC

SELECT r.id, p.id AS payLogId, p.pay_no, r.resource_name, r.customer_name, r.fee_name, r.bill_period, p.pay_type, p.pay_method, p.total_amount, p.discount_amount, p.overdue_amount, p.pre_pay_amount, p.pay_amount, p.creator_time AS payTime, p.note FROM resi_receivable r LEFT JOIN resi_pay_log p ON r.pay_log_id = p.id WHERE r.delete_time IS NULL
AND r.project_id = #{projectId}
AND r.resource_name LIKE CONCAT('%', #{resourceName}, '%')
AND r.customer_name LIKE CONCAT('%', #{customerName}, '%')
AND r.fee_name LIKE CONCAT('%', #{feeName}, '%')
AND p.pay_method = #{payMethod}
AND p.pay_type = #{payType}
AND p.pay_no LIKE CONCAT('%', #{payNo}, '%')
AND p.creator_time >= CONCAT(#{beginDate}, ' 00:00:00')
AND p.creator_time <= CONCAT(#{endDate}, ' 23:59:59')
AND r.project_id IN
#{pid}
ORDER BY p.creator_time DESC, r.creator_time DESC

SELECT bill_period, fee_name, COUNT(*) AS totalCount, SUM(receivable) AS receivableAmount, SUM(paid_amount) AS paidAmount, ROUND(IFNULL(SUM(paid_amount) / NULLIF(SUM(receivable), 0), 0) * 100, 2) AS collectionRate, SUM(receivable - paid_amount) AS unpaidAmount FROM resi_receivable WHERE delete_time IS NULL
AND project_id = #{projectId}
AND fee_id = #{feeId}
AND bill_period LIKE CONCAT(#{year}, '%')
AND bill_period >= #{beginPeriod}
AND bill_period <= #{endPeriod}
AND project_id IN
#{pid}
GROUP BY bill_period, fee_name ORDER BY bill_period DESC, fee_name

SELECT id, resource_name, customer_name, fee_name, fee_type, bill_period, num, price, total, overdue_fee, discount_amount, receivable, paid_amount, (receivable - paid_amount) AS arrearsAmount, remark FROM resi_receivable WHERE delete_time IS NULL AND pay_state = '0'
AND project_id = #{projectId}
AND resource_id IN ( SELECT id FROM resi_room WHERE building_id = #{buildingId} )
AND resource_name LIKE CONCAT('%', #{resourceName}, '%')
AND customer_name LIKE CONCAT('%', #{customerName}, '%')
AND fee_id = #{feeId}
AND bill_period = #{billPeriod}
AND fee_type = #{feeType}
AND project_id IN
#{pid}
ORDER BY bill_period ASC, resource_name

SELECT id, resource_name, customer_name, fee_name, fee_type, bill_period, num, price, total, overdue_fee, discount_amount, receivable, pay_state, paid_amount, pay_time, gen_batch, remark FROM resi_receivable WHERE delete_time IS NULL
AND project_id = #{projectId}
AND bill_period = #{billPeriod}
AND fee_id = #{feeId}
AND pay_state = #{payState}
AND resource_name LIKE CONCAT('%', #{resourceName}, '%')
AND customer_name LIKE CONCAT('%', #{customerName}, '%')
AND fee_type = #{feeType}
AND project_id IN
#{pid}
ORDER BY creator_time DESC
